parameters.jsCode:
const inputItem = $input.all()[0].json;
const judgeScores = inputItem.output || {};
const hasCitations = judgeScores.hasCitations === true;
const relevance = parseFloat(judgeScores.relevance) || 0;
const specificity = parseFloat(judgeScores.specificity) || 0;
const completeness = parseFloat(judgeScores.completeness) || 0;
const confidence = parseFloat(judgeScores.confidence) || 0;
const compositeScore = (relevance + specificity + completeness + confidence) / 4;
const pct = (Math.min(Math.max(compositeScore, 0), 1) * 100).toFixed(0);
const sessionId = inputItem.sessionId || '';
const now = new Date().toLocaleString("ru-RU", { timeZone: "Europe/Moscow" });
const category = $('Categorize').first().json.output.category || "general";
const agentOutput = String($('Legal/HR AI Agent').first().json.output || '');
const sourceCount = judgeScores.sourceCount;
const lowConf = compositeScore < 0.6;
var catLabel = "Общий вопрос";
var disclaimer = "";
if (category === "hr") {
  catLabel = "Кадровый вопрос";
  disclaimer = "Ответ основан на внутренних HR-документах. Источники имеют приоритет.";
} else if (category === "legal") {
  catLabel = "Юридический вопрос";
  disclaimer = "Данный ответ носит информационный характер. Для финальных документов требуется проверка специалистом.";
} else {
  disclaimer = "Ответ основан на доступных документах. Первоисточники имеют приоритет.";
}
var header = "**Категория:** " + catLabel;
header += "\n\n**Общая уверенность:** " + pct + "%";
if (!hasCitations) header += "  (нет источников)";
if (lowConf) header += "  (ниже порога 60%)";
header += "\n\n**Найдено источников:** " + sourceCount;
header += "\n\n**Источники:** " + (hasCitations ? "ДА" : "НЕТ");
header += "\n\n**Релевантность:** " + (relevance * 100).toFixed(0) + "%";
header += "\n\n**Специфичность:** " + (specificity * 100).toFixed(0) + "%";
header += "\n\n**Полнота:** " + (completeness * 100).toFixed(0) + "%";
header += "\n\n**Достоверность:** " + (confidence * 100).toFixed(0) + "%";
header += "\n\n---\n\n";
var footer = "\n\n---\n\n";
if (!hasCitations) {
  footer += "**Ответ без источников. Требуется проверка специалистом.**\n";
} else if (lowConf) {
  footer += "**Точность ниже порога. Рекомендуется проверка специалистом.**\n";
} else {
  footer += disclaimer + "\n";
}
footer += now;
return [{ json: { output: header + agentOutput + footer, sessionId: sessionId, hasCitations: hasCitations, sourceCount: sourceCount, relevance: relevance, specificity: specificity, completeness: completeness, confidence: confidence, compositeScore: compositeScore } }];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "hasCitations": {
      "type": "boolean",
      "description": "Does the answer cite specific documents, laws, or articles? If false, answer MUST NOT be shown."
    },
    "sourceCount": {
      "type": "number",
      "minimum": 0,
      "description": "How many sources are cited? Count actual sources: doc/doc_section/section_article - counts as a single source if related to the same doc. Same source: count only once"
    },
    "relevance": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Is the answer relevant to the question?"
    },
    "specificity": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Detailed and specific, or vague?"
    },
    "completeness": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Fully addresses the question?"
    },
    "confidence": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Is the answer really based on the ground truth and valid?"
    }
  },
  "required": ["hasCitations", "sourceCount", "relevance", "specificity", "completeness", "confidence"]
}

{
  "type": "object",
  "properties": {
    "category": {
      "type": "string",
      "enum": ["hr", "legal", "general"],
      "description": "HR: vacation, hiring, personnel, employees, recruitment, dismissal, staff policies. Legal: contracts, laws, regulations, labor code, rights, agreements, compliance. General: questions not specific to HR or legal domains."
    }
  },
  "required": ["category"]
}
